import{_ as t,o as d,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Integration API","description":"","frontmatter":{},"headers":[],"relativePath":"fr/advanced/api.md","filePath":"fr/advanced/api.md"}'),s={name:"fr/advanced/api.md"};function o(r,e,n,l,c,p){return d(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="integration-api" tabindex="-1">Integration API <a class="header-anchor" href="#integration-api" aria-label="Permalink to &quot;Integration API&quot;">​</a></h1><p>Accedez a vos donnees MyCompanyDesk de maniere programmatique via l&#39;API REST.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>L&#39;acces API necessite le plan <strong>Business</strong>.</p></div><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>L&#39;API MyCompanyDesk vous permet de :</p><ul><li>Creer et recuperer des factures, depenses et clients</li><li>Automatiser les flux de facturation</li><li>Integrer d&#39;autres outils professionnels</li><li>Creer des rapports personnalises</li><li>Synchroniser les donnees avec des systemes externes</li></ul><h2 id="authentification" tabindex="-1">Authentification <a class="header-anchor" href="#authentification" aria-label="Permalink to &quot;Authentification&quot;">​</a></h2><p>Toutes les requetes API necessitent une cle API envoyee dans l&#39;en-tete de la requete :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer YOUR_API_KEY</span></span></code></pre></div><h3 id="creer-une-cle-api" tabindex="-1">Creer une cle API <a class="header-anchor" href="#creer-une-cle-api" aria-label="Permalink to &quot;Creer une cle API&quot;">​</a></h3><ol><li>Allez dans <strong>Parametres &gt; Cles API</strong></li><li>Cliquez sur <strong>Generer une nouvelle cle</strong></li><li>Donnez a la cle un nom descriptif</li><li>Copiez la cle -- elle n&#39;est affichee qu&#39;une seule fois</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Conservez votre cle API en lieu sur. Ne la commitez jamais dans un depot de code source et ne la partagez jamais publiquement.</p></div><h2 id="url-de-base" tabindex="-1">URL de base <a class="header-anchor" href="#url-de-base" aria-label="Permalink to &quot;URL de base&quot;">​</a></h2><p>Tous les endpoints API sont disponibles a l&#39;adresse :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.mycompanydesk.com/api</span></span></code></pre></div><h2 id="endpoints-principaux" tabindex="-1">Endpoints principaux <a class="header-anchor" href="#endpoints-principaux" aria-label="Permalink to &quot;Endpoints principaux&quot;">​</a></h2><h3 id="clients" tabindex="-1">Clients <a class="header-anchor" href="#clients" aria-label="Permalink to &quot;Clients&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/customers</code></td><td>Lister tous les clients</td></tr><tr><td><code>POST</code></td><td><code>/customers</code></td><td>Creer un client</td></tr><tr><td><code>GET</code></td><td><code>/customers/:id</code></td><td>Obtenir un client</td></tr><tr><td><code>PUT</code></td><td><code>/customers/:id</code></td><td>Mettre a jour un client</td></tr><tr><td><code>DELETE</code></td><td><code>/customers/:id</code></td><td>Supprimer un client</td></tr></tbody></table><h3 id="factures" tabindex="-1">Factures <a class="header-anchor" href="#factures" aria-label="Permalink to &quot;Factures&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/invoices</code></td><td>Lister toutes les factures</td></tr><tr><td><code>POST</code></td><td><code>/invoices</code></td><td>Creer une facture</td></tr><tr><td><code>GET</code></td><td><code>/invoices/:id</code></td><td>Obtenir une facture</td></tr><tr><td><code>PUT</code></td><td><code>/invoices/:id</code></td><td>Mettre a jour une facture</td></tr><tr><td><code>DELETE</code></td><td><code>/invoices/:id</code></td><td>Supprimer une facture</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/send</code></td><td>Envoyer une facture</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/mark-paid</code></td><td>Marquer comme payee</td></tr></tbody></table><h3 id="depenses" tabindex="-1">Depenses <a class="header-anchor" href="#depenses" aria-label="Permalink to &quot;Depenses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/expenses</code></td><td>Lister toutes les depenses</td></tr><tr><td><code>POST</code></td><td><code>/expenses</code></td><td>Creer une depense</td></tr><tr><td><code>GET</code></td><td><code>/expenses/:id</code></td><td>Obtenir une depense</td></tr><tr><td><code>PUT</code></td><td><code>/expenses/:id</code></td><td>Mettre a jour une depense</td></tr><tr><td><code>DELETE</code></td><td><code>/expenses/:id</code></td><td>Supprimer une depense</td></tr></tbody></table><h3 id="projets" tabindex="-1">Projets <a class="header-anchor" href="#projets" aria-label="Permalink to &quot;Projets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/projects</code></td><td>Lister tous les projets</td></tr><tr><td><code>POST</code></td><td><code>/projects</code></td><td>Creer un projet</td></tr><tr><td><code>GET</code></td><td><code>/projects/:id</code></td><td>Obtenir un projet</td></tr><tr><td><code>PUT</code></td><td><code>/projects/:id</code></td><td>Mettre a jour un projet</td></tr></tbody></table><h3 id="recherche" tabindex="-1">Recherche <a class="header-anchor" href="#recherche" aria-label="Permalink to &quot;Recherche&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/search?q=term&amp;type=entity</code></td><td>Rechercher parmi les entites</td></tr></tbody></table><h2 id="filtrage" tabindex="-1">Filtrage <a class="header-anchor" href="#filtrage" aria-label="Permalink to &quot;Filtrage&quot;">​</a></h2><p>Les endpoints de liste prennent en charge les parametres de requete pour le filtrage :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/invoices?status=sent&amp;customer_id=123&amp;limit=50</span></span></code></pre></div><p>Filtres courants :</p><ul><li><code>status</code> -- Filtrer par statut</li><li><code>customer_id</code> -- Filtrer par client</li><li><code>project_id</code> -- Filtrer par projet</li><li><code>limit</code> -- Nombre de resultats (par defaut : 50)</li><li><code>offset</code> -- Decalage de pagination</li></ul><h2 id="limitation-de-debit" tabindex="-1">Limitation de debit <a class="header-anchor" href="#limitation-de-debit" aria-label="Permalink to &quot;Limitation de debit&quot;">​</a></h2><p>Les requetes API sont soumises a une limitation de debit pour garantir une utilisation equitable :</p><ul><li>La limite standard s&#39;applique par cle API</li><li>Le depassement de la limite renvoie une reponse <code>429 Too Many Requests</code></li><li>Incluez une strategie de reessai dans votre integration</li></ul><h2 id="gestion-des-erreurs" tabindex="-1">Gestion des erreurs <a class="header-anchor" href="#gestion-des-erreurs" aria-label="Permalink to &quot;Gestion des erreurs&quot;">​</a></h2><p>L&#39;API renvoie des codes de statut HTTP standard :</p><table tabindex="0"><thead><tr><th>Code</th><th>Description</th></tr></thead><tbody><tr><td><code>200</code></td><td>Succes</td></tr><tr><td><code>201</code></td><td>Cree</td></tr><tr><td><code>400</code></td><td>Requete invalide (verifiez vos parametres)</td></tr><tr><td><code>401</code></td><td>Non autorise (cle API invalide)</td></tr><tr><td><code>403</code></td><td>Interdit (permissions insuffisantes)</td></tr><tr><td><code>404</code></td><td>Non trouve</td></tr><tr><td><code>429</code></td><td>Debit limite</td></tr><tr><td><code>500</code></td><td>Erreur serveur</td></tr></tbody></table><p>Les reponses d&#39;erreur incluent un corps JSON :</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Description de ce qui s&#39;est mal passe&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Configurez des webhooks pour recevoir des notifications en temps reel lorsque des evenements se produisent :</p><ul><li>Facture envoyee</li><li>Facture payee</li><li>Client cree</li><li>Depense ajoutee</li></ul><p>Configurez les webhooks dans <strong>Parametres &gt; Cles API &gt; Webhooks</strong>.</p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez la pagination pour les grands ensembles de donnees</li><li>Mettez en cache les reponses lorsque c&#39;est possible pour reduire les appels API</li><li>Implementez une logique de reessai avec un backoff exponentiel pour les limites de debit</li><li>Utilisez les webhooks au lieu du polling pour les mises a jour en temps reel</li></ul>`,45)])])}const b=t(s,[["render",o]]);export{h as __pageData,b as default};
